// ============================================================
//  N8N – Code Node  |  Parser robusto de NF-e
//  Trata: string JSON escapada, objeto direto, array, texto
//  quebrado, campos ausentes, etc.
// ============================================================

function parseNFe(input) {
  // ---------------------------------------------------------
  // 1. NORMALIZA A ENTRADA – extrai um objeto JS de qualquer coisa
  // ---------------------------------------------------------
  let raw = input;

  // Se vier um array, pega o primeiro elemento
  if (Array.isArray(raw)) raw = raw[0];

  // Se vier um objeto com chave "query", desembrulha
  if (raw && typeof raw === 'object' && 'query' in raw) raw = raw.query;

  // Se agora for string, tenta fazer o parse
  if (typeof raw === 'string') {
    // Remove escapes de nova linha e tabs desnecessários
    let cleaned = raw
      .replace(/\\n/g, ' ')
      .replace(/\\t/g, ' ')
      .replace(/\\/g, '')          // remove barras sobrando
      .replace(/\s+/g, ' ')
      .trim();

    // Tenta JSON.parse direto
    try {
      raw = JSON.parse(cleaned);
    } catch (_) {
      // Se falhar, tenta extrair o JSON com regex (pega o maior bloco {…})
      const match = cleaned.match(/\{[\s\S]*\}/);
      if (match) {
        try { raw = JSON.parse(match[0]); } catch (__) { raw = {}; }
      } else {
        raw = {};
      }
    }
  }

  // Garante que raw é objeto
  if (typeof raw !== 'object' || raw === null) raw = {};

  // ---------------------------------------------------------
  // 2. HELPERS para leitura segura de campos
  // ---------------------------------------------------------
  const get = (obj, ...keys) => {
    for (const key of keys) {
      if (obj && typeof obj === 'object' && key in obj) return obj[key];
    }
    return null;
  };

  const str = (v) => (v == null ? null : String(v).trim() || null);

  const num = (v) => {
    if (v == null) return null;
    const n = parseFloat(String(v).replace(/\./g, '').replace(',', '.'));
    return isNaN(n) ? null : n;
  };

  // ---------------------------------------------------------
  // 3. MONTA O JSON FINAL NORMALIZADO
  // ---------------------------------------------------------
  const emitente   = get(raw, 'emitente')   || {};
  const dest       = get(raw, 'destinatario') || {};
  const endDest    = get(dest, 'endereco')  || {};
  const nf         = get(raw, 'nota_fiscal') || {};
  const transp     = get(raw, 'transporte') || {};
  const transporta = get(transp, 'transportadora') || {};
  const volumes    = get(transp, 'volumes')  || {};
  const entrega    = get(raw, 'entrega')    || {};
  const confirm    = get(raw, 'confirmacao') || {};

  const naoInf = (v) => (str(v) === 'NAO_INFORMADO' ? null : str(v));

  return {
    emitente: {
      razao_social : str(get(emitente, 'razao_social')),
      cnpj         : str(get(emitente, 'cnpj')),
    },

    destinatario: {
      razao_social : str(get(dest, 'razao_social')),
      cnpj         : str(get(dest, 'cnpj')),
      endereco: {
        logradouro : str(get(endDest, 'logradouro')),
        bairro     : str(get(endDest, 'bairro')),
        municipio  : str(get(endDest, 'municipio')),
        uf         : str(get(endDest, 'uf')),
        cep        : str(get(endDest, 'cep')),
      },
    },

    nota_fiscal: {
      numero            : str(get(nf, 'numero')),
      serie             : str(get(nf, 'serie')),
      chave_acesso      : str(get(nf, 'chave_acesso')),
      natureza_operacao : str(get(nf, 'natureza_operacao')),
      data_emissao      : str(get(nf, 'data_emissao')),
      hora_emissao      : str(get(nf, 'hora_emissao')),
      valor_produtos    : num(get(nf, 'valor_produtos')),
      valor_frete       : num(get(nf, 'valor_frete')),
      valor_total       : num(get(nf, 'valor_total')),
    },

    transporte: {
      transportadora: {
        razao_social : str(get(transporta, 'razao_social')),
        cnpj         : str(get(transporta, 'cnpj')),
      },
      volumes: {
        quantidade   : naoInf(get(volumes, 'quantidade')),
        especie      : str(get(volumes, 'especie')),
        peso_bruto   : num(get(volumes, 'peso_bruto')),
        peso_liquido : num(get(volumes, 'peso_liquido')),
      },
    },

    entrega: {
      endereco_fiscal   : str(get(entrega, 'endereco_fiscal')),
      endereco_entrega  : str(get(entrega, 'endereco_entrega')),
      endereco_utilizar : str(get(entrega, 'endereco_utilizar')),
      numero_pedido     : str(get(entrega, 'numero_pedido')),
      observacoes       : naoInf(get(entrega, 'observacoes')),
    },

    confirmacao: {
      confirmado_por_entregador : Boolean(get(confirm, 'confirmado_por_entregador')),
      data_confirmacao          : str(get(confirm, 'data_confirmacao')),
      hora_confirmacao          : str(get(confirm, 'hora_confirmacao')),
    },
  };
}

// ============================================================
//  PONTO DE ENTRADA DO N8N
// ============================================================
const items = $input.all();
const output = [];

for (const item of items) {
  try {
    // Tenta pegar o dado de várias formas possíveis
    const raw =
      item.json?.query ??   // formato atual (foto)
      item.json ??           // objeto direto
      item;                  // fallback

    const nfe = parseNFe(raw);

    output.push({ json: nfe });
  } catch (err) {
    // Nunca deixa o workflow quebrar – devolve o erro junto
    output.push({
      json: {
        erro      : true,
        mensagem  : err.message,
        item_raw  : item?.json ?? null,
      },
    });
  }
}

return output;
